using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using verii_metivon_api.Modules.Shipping.Domain.Entities;
namespace verii_metivon_api.Modules.Shipping.Infrastructure.Persistence.Configurations;
public sealed class ShipmentConfiguration:IEntityTypeConfiguration<Shipment>{public void Configure(EntityTypeBuilder<Shipment>b){b.ToTable("RII_SHIPMENTS");b.HasIndex(x=>x.ShipmentNumber).IsUnique();b.Property(x=>x.ShipmentNumber).HasMaxLength(40).IsRequired();b.HasOne(x=>x.SalesOrder).WithMany().HasForeignKey(x=>x.SalesOrderId).OnDelete(DeleteBehavior.Restrict);b.HasOne<verii_metivon_api.Modules.TradeOperations.Domain.Entities.TradeDossier>().WithMany().HasForeignKey(x=>x.TradeDossierId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class ShipmentLineConfiguration:IEntityTypeConfiguration<ShipmentLine>{public void Configure(EntityTypeBuilder<ShipmentLine>b){b.ToTable("RII_SHIPMENT_LINES");b.HasIndex(x=>new{x.ShipmentId,x.LineNumber}).IsUnique();b.Property(x=>x.Quantity).HasPrecision(24,8);b.HasOne(x=>x.Shipment).WithMany(x=>x.Lines).HasForeignKey(x=>x.ShipmentId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class DeliveryNoteConfiguration:IEntityTypeConfiguration<DeliveryNote>{public void Configure(EntityTypeBuilder<DeliveryNote>b){b.ToTable("RII_DELIVERY_NOTES");b.HasIndex(x=>x.DeliveryNoteNumber).IsUnique();b.HasIndex(x=>x.GibUuid).IsUnique().HasFilter("[GibUuid] IS NOT NULL");b.HasOne(x=>x.Shipment).WithOne(x=>x.DeliveryNote).HasForeignKey<DeliveryNote>(x=>x.ShipmentId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class ShippingParameterSettingsConfiguration:IEntityTypeConfiguration<ShippingParameterSettings>{public void Configure(EntityTypeBuilder<ShippingParameterSettings>b){b.ToTable("RII_SHIPPING_PARAMETERS",t=>t.HasCheckConstraint("CK_RII_SHIPPING_PARAMETERS_MAX_LINES","[MaximumLinesPerShipment] >= 1 AND [MaximumLinesPerShipment] <= 10000"));b.HasKey(x=>x.Id);b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>new{x.BranchId,x.WarehouseId}).IsUnique().HasFilter("[IsDeleted] = 0");b.Property(x=>x.DeliveryNoteScenario).HasMaxLength(30).IsRequired();b.Property(x=>x.InventoryCurrencyCode).HasMaxLength(3).IsUnicode(false).IsRequired();b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.Branch).WithMany().HasForeignKey(x=>x.BranchId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.Warehouse).WithMany().HasForeignKey(x=>x.WarehouseId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.InventoryCurrency).WithMany().HasForeignKey(x=>x.InventoryCurrencyId).OnDelete(DeleteBehavior.Restrict);}}
